import { forwardRef, type ReactNode } from 'react';
import { cn } from '../../utils/cn';
import styles from './EmptyState.module.css';

export interface EmptyStateProps {
  icon?: ReactNode;
  title: string;
  description?: string;
  action?: ReactNode;
  className?: string;
}

export const EmptyState = forwardRef<HTMLDivElement, EmptyStateProps>(
  function EmptyState(
    {
      icon,
      title,
      description,
      action,
      className,
      'data-testid': dataTestId = 'tatva-emptystate',
    }: EmptyStateProps & { 'data-testid'?: string },
    ref,
  ) {
    return (
      <div
        ref={ref}
        className={cn(styles.empty, className)}
        data-testid={dataTestId}
      >
        {icon && (
          <div className={styles.icon} aria-hidden="true">
            {icon}
          </div>
        )}
        <div className={styles.title}>{title}</div>
        {description && <div className={styles.description}>{description}</div>}
        {action && <div className={styles.action}>{action}</div>}
      </div>
    );
  },
);

.empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--tatva-space-3);
  padding: var(--tatva-space-8) var(--tatva-space-6);
  text-align: center;
  font-family: var(--tatva-font-family);
  color: var(--tatva-color-fg);
}

.icon {
  color: var(--tatva-color-neutral-400);
}

.title {
  font-size: var(--tatva-font-size-lg);
  font-weight: var(--tatva-font-weight-semibold);
}

.description {
  color: var(--tatva-color-fg-muted);
  font-size: var(--tatva-font-size-sm);
  max-width: 360px;
}

.action {
  margin-top: var(--tatva-space-2);
}
